#include <stdio.h>
#include <math.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int k = 0;
        while((1<<k) < N+1) k++;
        for(int i=0;i<N;i++){
            int gray_i = i ^ (i>>1);
            int gray_next = (i+1) ^ ((i+1)>>1);
            int diff = gray_i ^ gray_next; // power of two
            int bit = __builtin_ctz(diff); // trailing zeros, GCC builtin
            printf("%d", bit+1);
            if(i+1<N) printf(" ");
        }
        if(T) printf("\n");
    }
    return 0;
}

