    const gray_i = i ^ (i >> 1);
    const gray_next = (i + 1) ^ ((i + 1) >> 1);
    const diff = gray_i ^ gray_next; // power of two
    // trailing zeros
    let bit = 0;
    let d = diff;
    while ((d & 1) === 0) { d >>= 1; bit++; }
    line.push(String(bit + 1));
  }
  outputs.push(line.join(' '));
